function report = runDenseProfile(options)
%RUNDENSEPROFILE Profile the tiled dense CPU height sweep.
%
% The height grid is chosen only after measuring median ||dw/dZ|| in
% pixels/metre. Memory is a conservative accounting of tracked MATLAB arrays,
% not operating-system peak RSS. Traceability: algo/main.tex Secs. 10.4,
% 11.2-11.4, and 14.6; Eqs. (52)-(56), (126)-(129), and Algorithm 1.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [128, 144]
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [64, 72]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.Channel (1, 1) string ...
        {mustBeMember(options.Channel, ...
        ["Zncc", "Census", "NormalizedGradient", "PointSpin2", ...
        "Spin2T0", "Spin2T1", "Spin2T2", "Spin2T3", "Spin2T4", ...
        "HybridZnccSpin2T3"])} = "Zncc"
    options.Channels (1, :) string ...
        {mustBeNonempty, mustBeMember(options.Channels, ...
        ["Zncc", "Census", "NormalizedGradient", "PointSpin2", ...
        "Spin2T0", "Spin2T1", "Spin2T2", "Spin2T3", "Spin2T4", ...
        "HybridZnccSpin2T3"])} = ...
        ["Zncc", "Census", "NormalizedGradient", "PointSpin2", ...
        "Spin2T0", "Spin2T1", "Spin2T2", "Spin2T3", "Spin2T4", ...
        "HybridZnccSpin2T3"]
    options.HeightRangeMetres (1, 2) double ...
        {mustBeFinite, mustBeIncreasing} = [-50, 50]
    options.TargetMotionPerLabelPixels (1, 1) double ...
        {mustBeFinite, mustBePositive} = 0.25
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.StoreCostVolumes (1, 1) logical = false
    options.RunOptimizedZncc (1, 1) logical = false
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "double"
end

renderer = SyntheticPinholeRenderer("dense-profile", options.ImageSize, ...
    Supersample=2, PsfSigmaPixels=0.5, TextureSeed=71);
timer = tic;
pair = renderer.renderPair;
renderSeconds = toc(timer);

geometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
[p, referenceValid] = samplePoints(pair.ReferenceValid);
z0 = mean(options.HeightRangeMetres);
[~, kappa, derivativeValid] = geometry.heightDerivative(p, z0);
validObservability = referenceValid & derivativeValid & isfinite(kappa) ...
    & kappa > 0;
if ~any(validObservability)
    error("runDenseProfile:NoObservableSamples", ...
        "No valid positive dw/dZ samples were available for label spacing.");
end
medianObservability = median(kappa(validObservability));
requestedSpacing = options.TargetMotionPerLabelPixels ...
    ./ medianObservability;
nIntervals = max(2, ceil(diff(options.HeightRangeMetres) ...
    ./ requestedSpacing));
z = linspace(options.HeightRangeMetres(1), ...
    options.HeightRangeMetres(2), nIntervals + 1);
actualSpacing = z(2) - z(1);

levels = 2 ^ renderer.BitDepth - 1;
requestedChannels = unique([options.Channels, options.Channel], "stable");
prepareGradients = ~all(ismember( ...
    requestedChannels, ["Zncc", "Census"]));
timer = tic;
curve = HeightCostCurve(geometry, ...
    cast(pair.ReferenceImage, options.WorkingPrecision) ...
    ./ cast(levels, options.WorkingPrecision), ...
    cast(pair.MovingImage, options.WorkingPrecision) ...
    ./ cast(levels, options.WorkingPrecision), ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    PrepareGradients=prepareGradients, ...
    WorkingPrecision=options.WorkingPrecision);
preparationSeconds = toc(timer);
dense = DenseHeightSweep(curve);
result = dense.runTiled(z, Channel=options.Channel, ...
    Channels=options.Channels, ...
    TileSize=options.TileSize, LabelBlockSize=options.LabelBlockSize, ...
    StoreCostVolumes=options.StoreCostVolumes, ...
    UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
    ProfileOperations=true);
optimized = struct;
equivalence = struct;
if options.RunOptimizedZncc
    optimized = dense.runZnccOptimized(z, ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=options.StoreCostVolumes, ...
        UseParallel=options.UseParallel, NumWorkers=options.NumWorkers, ...
        WorkingPrecision=options.WorkingPrecision);
    if options.StoreCostVolumes
        referenceZncc = result.CostVolumeByChannel.Zncc;
        equivalence = HeightSweepEquivalence.compare( ...
            referenceZncc, optimized.CostVolume, ...
            CostTolerance=1e-10, TieTolerance=1e-9);
    end
end

profile = result.Runtime.OperationProfiling;
seconds = profile.CumulativeWorkerSeconds(:);
fraction = seconds ./ max(sum(seconds), eps);
operationResults = table(profile.OperationNames(:), seconds, fraction, ...
    VariableNames=["Operation", "CumulativeWorkerSeconds", ...
    "FractionOfProfiledWorkerTime"]);
operationCounts = table(profile.OperationCountNames(:), ...
    profile.OperationCounts(:), ...
    VariableNames=["Operation", "Count"]);
featureBytes = featurePayloadBytes(curve.Reference) ...
    + featurePayloadBytes(curve.Moving);
costInfo = whos("result");
costVolume = result.CostVolume; %#ok<NASGU>
costVolumeInfo = whos("costVolume");
costVolumeBytes = costVolumeInfo.bytes;
memoryNames = ["OutputArrays", "RetainedTileResults", ...
    "ConcurrentReturnedBlocks", "EstimatedTrackedPeak"];
bytes = [result.Runtime.OutputArrayBytes; ...
    result.Runtime.RetainedTileResultBytes; ...
    result.Runtime.MaximumConcurrentBlockResultBytes; ...
    result.Runtime.EstimatedPeakTrackedBytes];
memoryResults = table(memoryNames(:), bytes, bytes ./ 2 ^ 20, ...
    VariableNames=["Component", "Bytes", "Mebibytes"]);

report = struct( ...
    "ImageSize", options.ImageSize, ...
    "Channel", options.Channel, ...
    "ComputedChannels", result.ComputedChannels, ...
    "HeightLabelsMetres", z, ...
    "MedianObservabilityPixelsPerMetre", medianObservability, ...
    "LabelSpacingMetres", actualSpacing, ...
    "MedianMotionPerLabelPixels", ...
    medianObservability .* actualSpacing, ...
    "RenderSeconds", renderSeconds, ...
    "PreparationSeconds", preparationSeconds, ...
    "OperationResults", operationResults, ...
    "OperationCounts", operationCounts, ...
    "FeaturePreparationBytes", featureBytes, ...
    "GradientsPrepared", prepareGradients, ...
    "WorkingPrecision", options.WorkingPrecision, ...
    "CostVolumeBytes", costVolumeBytes, ...
    "ResultStructBytes", costInfo.bytes, ...
    "MemoryResults", memoryResults, ...
    "DenseResult", result, ...
    "OptimizedZnccResult", optimized, ...
    "OptimizedZnccEquivalence", equivalence, ...
    "MemoryDefinition", result.Runtime.MemoryDefinition, ...
    "CoordinateConvention", ...
    "one-based [x,y]=[column,row] pixel centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0");

fprintf("Dense profile: %d x %d pixels, %d labels, %s, %d workers\n", ...
    options.ImageSize(1), options.ImageSize(2), numel(z), ...
    result.Runtime.Execution, result.Runtime.NumWorkers);
fprintf("  channels: %s (primary %s)\n", ...
    strjoin(result.ComputedChannels, ", "), result.Channel);
fprintf("  render %.3f s, prepare %.3f s, sweep %.3f s, %.3g pixel-label/s\n", ...
    renderSeconds, preparationSeconds, result.Runtime.EvaluationSeconds, ...
    result.Runtime.PixelLabelsPerSecond);
fprintf("  median dw/dZ %.6g px/m, label spacing %.6g m (%.6g px)\n", ...
    medianObservability, actualSpacing, ...
    report.MedianMotionPerLabelPixels);
disp(operationResults);
disp(operationCounts);
disp(memoryResults);
if options.RunOptimizedZncc
    fprintf("  optimized ZNCC %.3f s, %.3g pixel-label/s\n", ...
        optimized.Runtime.EvaluationSeconds, ...
        optimized.Runtime.PixelLabelsPerSecond);
    if options.StoreCostVolumes
        fprintf("  optimized/reference max |delta cost| %.3e; pass %s\n", ...
            equivalence.MaximumAbsoluteCostDifference, ...
            string(equivalence.Pass));
    end
end
end

function bytes = featurePayloadBytes(feature)
names = properties(feature);
bytes = 0;
for k = 1:numel(names)
    value = feature.(names{k}); %#ok<NASGU>
    info = whos("value");
    bytes = bytes + info.bytes;
end
end

function [p, valid] = samplePoints(mask)
nr = size(mask, 1);
nc = size(mask, 2);
ny = min(nr, 16);
nx = min(nc, 16);
y = unique(round(linspace(1, nr, ny)));
x = unique(round(linspace(1, nc, nx)));
[xx, yy] = meshgrid(x, y);
p = [xx(:), yy(:)];
valid = mask(sub2ind(size(mask), p(:, 2), p(:, 1)));
end

function mustBeIncreasing(x)
if x(2) <= x(1)
    error("runDenseProfile:HeightRangeNotIncreasing", ...
        "HeightRangeMetres must be strictly increasing.");
end
end
